import pytest
from requests.models import PreparedRequest

@pytest.fixture
def request():
    req = PreparedRequest()
    req.method = "GET"
    req.url = "http://example.com"
    req.headers = {"Content-Type": "application/json"}
    req._cookies = None
    req.body = None
    req.hooks = {}
    req._body_position = 0
    return req

def test_copy_method(request):
    copied_request = request.copy()
    assert copied_request.method == request.method

def test_copy_url(request):
    copied_request = request.copy()
    assert copied_request.url == request.url

def test_copy_headers(request):
    copied_request = request.copy()
    assert copied_request.headers == request.headers

def test_copy_cookies_none(request):
    copied_request = request.copy()
    assert copied_request._cookies is None

def test_copy_body_none(request):
    copied_request = request.copy()
    assert copied_request.body is None

def test_copy_hooks(request):
    copied_request = request.copy()
    assert copied_request.hooks == request.hooks

def test_copy_body_position(request):
    copied_request = request.copy()
    assert copied_request._body_position == request._body_position

def test_copy_headers_mutability(request):
    copied_request = request.copy()
    copied_request.headers["Content-Type"] = "text/plain"
    assert request.headers["Content-Type"] == "application/json"

def test_copy_with_cookies(request):
    request._cookies = {"session": "abc123"}
    copied_request = request.copy()
    assert copied_request._cookies == request._cookies

def test_copy_with_body(request):
    request.body = "sample body"
    copied_request = request.copy()
    assert copied_request.body == request.body

def test_copy_empty_request():
    empty_request = PreparedRequest()
    copied_request = empty_request.copy()
    assert copied_request.method is None
    assert copied_request.url is None
    assert copied_request.headers is None
    assert copied_request._cookies is None
    assert copied_request.body is None
    assert copied_request.hooks == {}
    assert copied_request._body_position == 0

