import pytest
from urllib.parse import urlsplit

@pytest.fixture
def url_builder():
    class URLBuilder:
        def __init__(self, url):
            self.url = url

        def path_url(self):
            url = []
            p = urlsplit(self.url)
            path = p.path
            if not path:
                path = "/"
            url.append(path)
            query = p.query
            if query:
                url.append("?")
                url.append(query)
            return "".join(url)

    return URLBuilder

def test_path_url_with_path(url_builder):
    builder = url_builder("http://example.com/path/to/resource?query=1")
    assert builder.path_url() == "/path/to/resource?query=1"

def test_path_url_without_path(url_builder):
    builder = url_builder("http://example.com?query=1")
    assert builder.path_url() == "/?query=1"

def test_path_url_empty_path(url_builder):
    builder = url_builder("http://example.com")
    assert builder.path_url() == "/"

def test_path_url_only_query(url_builder):
    builder = url_builder("http://example.com/?query=1")
    assert builder.path_url() == "/?query=1"

def test_path_url_no_query(url_builder):
    builder = url_builder("http://example.com/path/to/resource")
    assert builder.path_url() == "/path/to/resource"

def test_path_url_root(url_builder):
    builder = url_builder("http://example.com/")
    assert builder.path_url() == "/"

def test_path_url_with_special_characters(url_builder):
    builder = url_builder("http://example.com/path/to/resource?query=hello%20world")
    assert builder.path_url() == "/path/to/resource?query=hello%20world"

def test_path_url_with_empty_url(url_builder):
    builder = url_builder("")
    assert builder.path_url() == "/"

def test_path_url_with_fragment(url_builder):
    builder = url_builder("http://example.com/path#fragment")
    assert builder.path_url() == "/path"

def test_path_url_with_encoded_path(url_builder):
    builder = url_builder("http://example.com/path%20with%20spaces")
    assert builder.path_url() == "/path with spaces"

