import pytest
from urllib.parse import urlparse, urlunparse

def urldefragauth(url):
    scheme, netloc, path, params, query, fragment = urlparse(url)
    if not netloc:
        netloc, path = path, netloc
    netloc = netloc.rsplit("@", 1)[-1]
    return urlunparse((scheme, netloc, path, params, query, ""))

def test_urldefragauth_basic_url():
    url = "http://user:pass@example.com/path?query=value#fragment"
    assert urldefragauth(url) == "http://example.com/path?query=value"

def test_urldefragauth_no_authentication():
    url = "http://example.com/path?query=value#fragment"
    assert urldefragauth(url) == "http://example.com/path?query=value"

def test_urldefragauth_no_fragment():
    url = "http://user:pass@example.com/path?query=value"
    assert urldefragauth(url) == "http://example.com/path?query=value"

def test_urldefragauth_no_query_or_fragment():
    url = "http://user:pass@example.com/path"
    assert urldefragauth(url) == "http://example.com/path"

def test_urldefragauth_empty_url():
    url = ""
    assert urldefragauth(url) == ""

def test_urldefragauth_no_scheme():
    url = "example.com/path?query=value#fragment"
    assert urldefragauth(url) == "example.com/path?query=value"

def test_urldefragauth_multiple_authentication_parts():
    url = "http://user:pass1:pass2@example.com/path?query=value#fragment"
    assert urldefragauth(url) == "http://example.com/path?query=value"

def test_urldefragauth_only_fragment():
    url = "#fragment"
    assert urldefragauth(url) == ""

def test_urldefragauth_only_authentication():
    url = "http://user:pass@"
    assert urldefragauth(url) == "http://"

def test_urldefragauth_ftp_scheme():
    url = "ftp://user:pass@ftp.example.com/path#fragment"
    assert urldefragauth(url) == "ftp://ftp.example.com/path"

def test_urldefragauth_http_scheme_no_path():
    url = "http://user:pass@example.com#fragment"
    assert urldefragauth(url) == "http://example.com"

