import pytest
import socket
from your_module import address_in_network  # Replace 'your_module' with the actual module name

def test_address_in_network_valid_case():
    assert address_in_network("192.168.1.1", "192.168.1.0/24") is True

def test_address_in_network_different_subnet():
    assert address_in_network("192.168.1.1", "192.168.100.0/24") is False

def test_address_in_network_edge_case_same_network():
    assert address_in_network("192.168.1.255", "192.168.1.0/24") is True

def test_address_in_network_edge_case_network_address():
    assert address_in_network("192.168.1.0", "192.168.1.0/24") is True

def test_address_in_network_edge_case_broadcast_address():
    assert address_in_network("192.168.1.255", "192.168.1.0/24") is True

def test_address_in_network_invalid_ip_format():
    with pytest.raises(socket.error):
        address_in_network("999.999.999.999", "192.168.1.0/24")

def test_address_in_network_invalid_net_format():
    with pytest.raises(ValueError):
        address_in_network("192.168.1.1", "192.168.1.0/33")

def test_address_in_network_empty_ip():
    with pytest.raises(socket.error):
        address_in_network("", "192.168.1.0/24")

def test_address_in_network_empty_net():
    with pytest.raises(ValueError):
        address_in_network("192.168.1.1", "")

def test_address_in_network_invalid_ip_type():
    with pytest.raises(TypeError):
        address_in_network(12345, "192.168.1.0/24")

def test_address_in_network_invalid_net_type():
    with pytest.raises(TypeError):
        address_in_network("192.168.1.1", 12345)

