def test_parse_list_header_simple():
    assert parse_list_header('token1, token2, token3') == ['token1', 'token2', 'token3']

def test_parse_list_header_with_quotes():
    assert parse_list_header('token1, "quoted value", token2') == ['token1', 'quoted value', 'token2']

def test_parse_list_header_with_commas_in_quotes():
    assert parse_list_header('token1, "quoted, value", token2') == ['token1', 'quoted, value', 'token2']

def test_parse_list_header_with_spaces():
    assert parse_list_header(' token1 , " quoted value " , token2 ') == ['token1', 'quoted value', 'token2']

def test_parse_list_header_empty_string():
    assert parse_list_header('') == []

def test_parse_list_header_single_token():
    assert parse_list_header('token1') == ['token1']

def test_parse_list_header_only_quotes():
    assert parse_list_header('"quoted"') == ['quoted']

def test_parse_list_header_multiple_quotes():
    assert parse_list_header('"value1", "value2", "value3"') == ['value1', 'value2', 'value3']

def test_parse_list_header_mixed_quotes_and_tokens():
    assert parse_list_header('token1, "value2", token3, "value4"') == ['token1', 'value2', 'token3', 'value4']

def test_parse_list_header_invalid_format():
    with pytest.raises(ValueError):
        parse_list_header('token1, "value2, token3')

def test_parse_list_header_leading_trailing_commas():
    assert parse_list_header(', token1, "value2", token3, ') == ['token1', 'value2', 'token3']

def test_parse_list_header_case_sensitivity():
    assert parse_list_header('Token1, token2, TOKEN3') == ['Token1', 'token2', 'TOKEN3']

