    cookies1 = {'session_id': 'abc123'}
    cookies2 = {'user_id': 'user456'}
    prepared_request.prepare_cookies(cookies1)
    prepared_request.prepare_cookies(cookies2)
    assert prepared_request.headers["Cookie"] == "session_id=abc123"

