import pytest
import arrow
from datetime import datetime, timezone, timedelta

@pytest.fixture
def utc_arrow():
    return arrow.get(datetime(2023, 10, 1, 12, 0, 0, tzinfo=timezone.utc))

def test_to_us_pacific(utc_arrow):
    result = utc_arrow.to('US/Pacific')
    assert result == arrow.get(datetime(2023, 10, 1, 5, 0, 0, tzinfo=timezone(timedelta(hours=-7))))

def test_to_local(utc_arrow):
    result = utc_arrow.to('local')
    assert result.tzinfo is not None

def test_to_negative_offset(utc_arrow):
    result = utc_arrow.to('-07:00')
    assert result == arrow.get(datetime(2023, 10, 1, 5, 0, 0, tzinfo=timezone(timedelta(hours=-7))))

def test_to_positive_offset(utc_arrow):
    result = utc_arrow.to('+02:00')
    assert result == arrow.get(datetime(2023, 10, 1, 14, 0, 0, tzinfo=timezone(timedelta(hours=2))))

def test_to_invalid_timezone(utc_arrow):
    with pytest.raises(ValueError):
        utc_arrow.to('Invalid/Timezone')

def test_to_none_timezone(utc_arrow):
    with pytest.raises(ValueError):
        utc_arrow.to(None)

def test_to_fold(utc_arrow):
    dt = arrow.get(datetime(2023, 10, 29, 1, 30, 0, tzinfo=timezone(timedelta(hours=-5))))  # Before DST ends
    result = dt.to('US/Eastern')
    assert result.fold == 0  # Standard time

    dt = arrow.get(datetime(2023, 10, 29, 1, 30, 0, tzinfo=timezone(timedelta(hours=-5)), fold=1))  # After DST ends
    result = dt.to('US/Eastern')
    assert result.fold == 1  # Daylight saving time

def test_to_same_timezone(utc_arrow):
    result = utc_arrow.to('UTC')
    assert result == utc_arrow

def test_to_invalid_type(utc_arrow):
    with pytest.raises(TypeError):
        utc_arrow.to(123)

