def formatter():
    class MockFormatter:
        def __init__(self):
            self.and_word = "and"

        def _format_timeframe(self, timeframe, delta):
            return f"{delta} {timeframe}"

        def _format_relative(self, humanized, unit, value):
            return f"{humanized} ago" if value > 0 else f"{humanized} in the future"

    return MockFormatter()

def test_describe_multi_single_timeframe(formatter):
    result = formatter.describe_multi([("hours", 2)])
    assert result == "2 hours ago"

