    result = formatter.describe_multi([("hours", 0), ("minutes", 0)])
    assert result == "0 hours and 0 minutes ago"

def test_describe_multi_negative_timeframe(formatter):
    result = formatter.describe_multi([("hours", -1)])
    assert result == "-1 hours ago"

def test_describe_multi_mixed_timeframes(formatter):
    result = formatter.describe_multi([("hours", 1), ("minutes", 0), ("seconds", 30)])
    assert result == "1 hours and 0 minutes ago"

def test_describe_multi_edge_case(formatter):
    result = formatter.describe_multi([("days", 1), ("hours", 0), ("minutes", 0)])
    assert result == "1 days ago"

def test_describe_multi_empty_timeframes(formatter):
    result = formatter.describe_multi([])
    assert result == ""

def test_describe_multi_only_distance_empty(formatter):
    result = formatter.describe_multi([], only_distance=True)
    assert result == ""

def test_describe_multi_with_and_word(formatter):
    formatter.and_word = "and"
    result = formatter.describe_multi([("days", 1), ("hours", 2)])
    assert result == "1 days and 2 hours ago"

