import pytest

MAX_TIMESTAMP = 2**31 - 1  # Example maximum timestamp for seconds
MAX_TIMESTAMP_MS = MAX_TIMESTAMP * 1000  # Maximum for milliseconds
MAX_TIMESTAMP_US = MAX_TIMESTAMP_MS * 1000  # Maximum for microseconds

def test_normalize_timestamp_seconds():
    assert normalize_timestamp(1000.0) == 1000.0

def test_normalize_timestamp_milliseconds():
    assert normalize_timestamp(1000000.0) == 1000.0

def test_normalize_timestamp_microseconds():
    assert normalize_timestamp(1000000000.0) == 1000.0

