import pytest
from itertools import tee

def triplewise(iterable):
    t1, t2, t3 = tee(iterable, 3)
    next(t3, None)
    next(t3, None)
    next(t2, None)
    return zip(t1, t2, t3)

def test_triplewise_basic():
    result = list(triplewise('ABCDE'))
    assert result == [('A', 'B', 'C'), ('B', 'C', 'D'), ('C', 'D', 'E')]

def test_triplewise_empty():
    result = list(triplewise(''))
    assert result == []

def test_triplewise_single_element():
    result = list(triplewise('A'))
    assert result == []

def test_triplewise_two_elements():
    result = list(triplewise('AB'))
    assert result == []

def test_triplewise_three_elements():
    result = list(triplewise('ABC'))
    assert result == [('A', 'B', 'C')]

def test_triplewise_with_numbers():
    result = list(triplewise([1, 2, 3, 4]))
    assert result == [(1, 2, 3), (2, 3, 4)]

def test_triplewise_with_special_characters():
    result = list(triplewise('!@#'))
    assert result == [('!', '@', '#')]

def test_triplewise_with_repeated_elements():
    result = list(triplewise('AAB'))
    assert result == [('A', 'A', 'B')]

def test_triplewise_with_long_iterable():
    result = list(triplewise(range(10)))
    expected = [(i, i + 1, i + 2) for i in range(8)]
    assert result == expected

def test_triplewise_with_iterable_of_iterables():
    result = list(triplewise([(1, 2), (3, 4), (5, 6)]))
    assert result == [((1, 2), (3, 4), (5, 6))]

def test_triplewise_with_none():
    result = list(triplewise([None, None, None]))
    assert result == [(None, None, None)]

