import pytest

def test_rstrip_normal_case():
    iterable = (None, False, None, 1, 2, None, 3, False, None)
    pred = lambda x: x in {None, False, ''}
    assert list(rstrip(iterable, pred)) == [None, False, None, 1, 2, None, 3]

def test_rstrip_all_elements_removed():
    iterable = (None, False, None, False, None)
    pred = lambda x: x in {None, False}
    assert list(rstrip(iterable, pred)) == []

def test_rstrip_no_elements_removed():
    iterable = (1, 2, 3)
    pred = lambda x: x in {None, False, ''}
    assert list(rstrip(iterable, pred)) == [1, 2, 3]

