import pytest

def test_roundrobin_multiple_iterables():
    result = list(roundrobin('ABC', 'D', 'EF'))
    assert result == ['A', 'D', 'E', 'B', 'F', 'C']

def test_roundrobin_single_iterable():
    result = list(roundrobin('ABC'))
    assert result == ['A', 'B', 'C']

def test_roundrobin_empty_iterables():
    result = list(roundrobin())
    assert result == []

def test_roundrobin_empty_and_non_empty_iterables():
    result = list(roundrobin([], 'D', 'EF'))
    assert result == ['D', 'E', 'F']

def test_roundrobin_iterables_of_different_lengths():
    result = list(roundrobin('AB', 'CDE', 'F'))
    assert result == ['A', 'C', 'F', 'B', 'D', 'E']

def test_roundrobin_all_empty_iterables():
    result = list(roundrobin([], [], []))
    assert result == []

def test_roundrobin_large_iterables():
    result = list(roundrobin(range(100), range(50, 60), range(10)))
    assert result[:10] == [0, 50, 0, 1, 51, 1, 2, 52, 2, 3]  # Check first few elements

def test_roundrobin_non_string_iterables():
    result = list(roundrobin([1, 2], [3, 4, 5], [6]))
    assert result == [1, 3, 6, 2, 4, 5]

def test_roundrobin_iterables_with_none():
    result = list(roundrobin(['A', None], ['B', 'C']))
    assert result == ['A', 'B', None, 'C']

def test_roundrobin_iterables_with_empty_strings():
    result = list(roundrobin(['', 'B'], ['C', '']))
    assert result == ['', 'C', 'B', '']

