import pytest

def test_split_at_basic():
    result = list(split_at('abcdcba', lambda x: x == 'b'))
    assert result == [['a'], ['c', 'd', 'c'], ['a']]

def test_split_at_with_range():
    result = list(split_at(range(10), lambda n: n % 2 == 1))
    assert result == [[0], [2], [4], [6], [8], []]

def test_split_at_with_maxsplit():
    result = list(split_at(range(10), lambda n: n % 2 == 1, maxsplit=2))
    assert result == [[0], [2], [4, 5, 6, 7, 8, 9]]

def test_split_at_keep_separator():
    result = list(split_at('abcdcba', lambda x: x == 'b', keep_separator=True))
    assert result == [['a'], ['b'], ['c', 'd', 'c'], ['b'], ['a']]

