import pytest

class TestPeek:
    @pytest.fixture
    def iterator_with_items(self):
        return iter([1, 2, 3])

    @pytest.fixture
    def empty_iterator(self):
        return iter([])

    @pytest.fixture
    def custom_peek(self, iterator_with_items):
        class CustomPeek:
            def __init__(self, it):
                self._it = it
                self._cache = []

            def peek(self, default=_marker):
                if not self._cache:
                    try:
                        self._cache.append(next(self._it))
                    except StopIteration:
                        if default is _marker:
                            raise
                        return default
                return self._cache[0]

        return CustomPeek(iterator_with_items)

    def test_peek_next_item(self, custom_peek):
        assert custom_peek.peek() == 1

    def test_peek_multiple_calls(self, custom_peek):
        assert custom_peek.peek() == 1
        assert custom_peek.peek() == 1

    def test_peek_after_next(self, custom_peek):
